#!/usr/bin/env python3
"""
关键字命中率验证脚本
用于验证方案书中定义的日志关键字在实际日志文件中的命中情况
"""

import re
import json
import sys
from datetime import datetime, timedelta
from typing import List, Dict, Tuple

class KeywordValidator:
    def __init__(self, spec_file: str, log_file: str):
        self.spec_file = spec_file
        self.log_file = log_file
        self.keywords = self._extract_keywords_from_spec()

    def _extract_keywords_from_spec(self) -> Dict[str, List[str]]:
        """从方案书中提取关键字"""
        keywords = {
            "entry": [],
            "state_transition": [],
            "exception": [],
            "exit": []
        }

        try:
            with open(self.spec_file, 'r', encoding='utf-8') as f:
                content = f.read()

            # 提取入口标识
            entry_match = re.search(r'### 入口标识\n(.*?)(?=###|$)', content, re.DOTALL)
            if entry_match:
                for line in entry_match.group(1).split('\n'):
                    if line.strip().startswith('-'):
                        pattern = line.split('：', 1)[-1].strip()
                        if pattern:
                            keywords["entry"].append(pattern)

            # 提取状态转换标识
            state_match = re.search(r'### 状态转换标识\n(.*?)(?=###|$)', content, re.DOTALL)
            if state_match:
                for line in state_match.group(1).split('\n'):
                    if line.strip().startswith('-'):
                        pattern = line.split('：', 1)[-1].strip()
                        if pattern:
                            keywords["state_transition"].append(pattern)

            # 提取异常标识
            exception_match = re.search(r'### 异常标识\n(.*?)(?=###|$)', content, re.DOTALL)
            if exception_match:
                for line in exception_match.group(1).split('\n'):
                    if line.strip().startswith('-'):
                        pattern = line.split('：', 1)[-1].strip()
                        if pattern:
                            keywords["exception"].append(pattern)

            # 提取退出标识
            exit_match = re.search(r'### 退出标识\n(.*?)(?=###|$)', content, re.DOTALL)
            if exit_match:
                for line in exit_match.group(1).split('\n'):
                    if line.strip().startswith('-'):
                        pattern = line.split('：', 1)[-1].strip()
                        if pattern:
                            keywords["exit"].append(pattern)

        except Exception as e:
            print(f"提取关键字时出错: {e}")

        return keywords

    def _parse_time_window(self, failure_time: str, window_minutes: int = 10) -> Tuple[datetime, datetime]:
        """解析时间窗口"""
        try:
            # 尝试解析不同的时间格式
            time_formats = [
                "%Y/%m/%d %H:%M:%S",
                "%Y-%m-%d %H:%M:%S",
                "%H:%M:%S",
                "%H:%M"
            ]

            failure_dt = None
            for fmt in time_formats:
                try:
                    failure_dt = datetime.strptime(failure_time, fmt)
                    break
                except ValueError:
                    continue

            if failure_dt is None:
                raise ValueError(f"无法解析时间格式: {failure_time}")

            # 如果只有时间没有日期，假设是今天
            if failure_dt.year == 1900:
                today = datetime.now().date()
                failure_dt = datetime.combine(today, failure_dt.time())

            start_time = failure_dt - timedelta(minutes=window_minutes)
            end_time = failure_dt + timedelta(minutes=window_minutes)

            return start_time, end_time

        except Exception as e:
            print(f"解析时间窗口时出错: {e}")
            return None, None

    def validate_keywords(self, failure_time: str, window_minutes: int = 10) -> Dict:
        """验证关键字命中情况"""
        results = {
            "total_keywords": 0,
            "matched_keywords": 0,
            "match_details": {},
            "hit_rate": 0.0,
            "log_entries": []
        }

        try:
            with open(self.log_file, 'r', encoding='utf-8', errors='ignore') as f:
                log_content = f.readlines()
        except Exception as e:
            print(f"读取日志文件时出错: {e}")
            return results

        start_time, end_time = self._parse_time_window(failure_time, window_minutes)
        if not start_time or not end_time:
            print("时间窗口解析失败")
            return results

        # 统计总关键字数
        total_keywords = sum(len(patterns) for patterns in self.keywords.values())
        results["total_keywords"] = total_keywords

        matched_count = 0

        for category, patterns in self.keywords.items():
            results["match_details"][category] = {
                "patterns": patterns,
                "matches": [],
                "hit_count": 0
            }

            for pattern in patterns:
                try:
                    # 编译正则表达式
                    regex = re.compile(pattern, re.IGNORECASE)
                    pattern_matches = []

                    for i, line in enumerate(log_content):
                        # 简单的时间过滤（这里可以根据实际日志格式优化）
                        if regex.search(line):
                            pattern_matches.append({
                                "line_number": i + 1,
                                "content": line.strip(),
                                "pattern": pattern
                            })

                    if pattern_matches:
                        matched_count += 1
                        results["match_details"][category]["matches"].extend(pattern_matches)
                        results["match_details"][category]["hit_count"] += len(pattern_matches)

                except re.error as e:
                    print(f"正则表达式错误 '{pattern}': {e}")
                    continue

        results["matched_keywords"] = matched_count
        results["hit_rate"] = (matched_count / total_keywords * 100) if total_keywords > 0 else 0

        return results

    def generate_report(self, results: Dict, failure_time: str) -> str:
        """生成验证报告"""
        report = []
        report.append("# 关键字命中率验证报告")
        report.append(f"**故障时间**: {failure_time}")
        report.append(f"**日志文件**: {self.log_file}")
        report.append(f"**方案书**: {self.spec_file}")
        report.append("")

        report.append("## 命中率概览")
        report.append(f"- 总关键字数量: {results['total_keywords']}")
        report.append(f"- 命中关键字数量: {results['matched_keywords']}")
        report.append(f"- **命中率: {results['hit_rate']:.1f}%**")
        report.append("")

        if results['hit_rate'] >= 80:
            report.append("✅ **命中率良好** - 方案书关键字覆盖充分")
        elif results['hit_rate'] >= 50:
            report.append("⚠️  **命中率中等** - 建议补充部分关键字")
        else:
            report.append("❌ **命中率较低** - 需要重新设计关键字策略")

        report.append("")

        report.append("## 详细命中情况")

        for category, details in results['match_details'].items():
            category_names = {
                "entry": "入口标识",
                "state_transition": "状态转换",
                "exception": "异常标识",
                "exit": "退出标识"
            }

            report.append(f"### {category_names.get(category, category)}")
            report.append(f"- 模式数量: {len(details['patterns'])}")
            report.append(f"- 命中次数: {details['hit_count']}")

            if details['matches']:
                report.append("- 匹配示例:")
                for match in details['matches'][:3]:  # 只显示前3个匹配
                    report.append(f"  - 行 {match['line_number']}: `{match['content'][:100]}...`")
            else:
                report.append("- ⚠️ 无匹配内容")

            report.append("")

        return '\n'.join(report)


def main():
    if len(sys.argv) != 4:
        print("使用方法: python keyword_validator.py <方案书路径> <日志文件路径> <故障时间>")
        print("示例: python keyword_validator.py auto-lock.md test.log '2026/3/21 18:00:00'")
        sys.exit(1)

    spec_file = sys.argv[1]
    log_file = sys.argv[2]
    failure_time = sys.argv[3]

    validator = KeywordValidator(spec_file, log_file)
    results = validator.validate_keywords(failure_time)
    report = validator.generate_report(results, failure_time)

    print(report)

    # 保存报告到文件
    report_file = f"keyword_validation_report_{datetime.now().strftime('%Y%m%d_%H%M%S')}.md"
    with open(report_file, 'w', encoding='utf-8') as f:
        f.write(report)

    print(f"\n报告已保存到: {report_file}")


if __name__ == "__main__":
    main()

